//! Position mapping between a `.jsx`/`.tsx` source and its plain-`.ts` virtual
//! document (#1498).
//!
//! The virtual TS is built by [`super::virtual_ts`] as a sequence of
//! byte-range [`VizeMapping`]s: verbatim regions map their generated bytes back
//! to the identical source bytes, and each re-emitted JSX expression maps its
//! generated bytes back to the original expression's byte range. These helpers
//! turn an editor cursor (a source byte offset) into a virtual-TS LSP position
//! to query Corsa, and turn a Corsa response position/range back into source
//! coordinates.
//!
//! Unlike the SFC path there is no `.vue` → `.vue.ts` import rewrite for JSX,
//! so the mappings operate directly in the coordinate system Corsa sees — no
//! `ImportSourceMap` translation step is needed.

use vize_canon::virtual_ts::VizeMapping;

/// LSP range parts: `(start_line, end_line, start_character, end_character)`.
pub(super) type LspRangeParts = (u32, u32, u32, u32);

/// Map a source byte offset to an LSP position in the virtual TS.
///
/// Picks the mapping whose `src_range` contains `source_offset` (preferring a
/// re-emitted expression mapping over the enclosing verbatim region when both
/// match, so a cursor inside `{props.msg}` lands on the re-emitted `props.msg`
/// rather than the verbatim wrapper). Returns the `(line, character)` of the
/// corresponding generated byte.
pub(super) fn source_offset_to_virtual_position(
    virtual_ts: &str,
    mappings: &[VizeMapping],
    source_offset: usize,
) -> Option<(u32, u32)> {
    let mapping = mapping_for_source_offset(mappings, source_offset)?;
    let relative = source_offset.saturating_sub(mapping.src_range.start);
    let gen_len = mapping
        .gen_range
        .end
        .saturating_sub(mapping.gen_range.start);
    let gen_offset = mapping
        .gen_range
        .start
        .saturating_add(relative.min(gen_len));
    Some(byte_offset_to_position(virtual_ts, gen_offset))
}

/// Map a virtual-TS LSP range back to a source LSP range.
///
/// Used to translate a Corsa hover/definition range (in virtual-TS
/// coordinates) back onto the original `.jsx`/`.tsx` document.
pub(super) fn virtual_range_to_source(
    virtual_ts: &str,
    source: &str,
    mappings: &[VizeMapping],
    start_line: u32,
    start_character: u32,
    end_line: u32,
    end_character: u32,
) -> Option<LspRangeParts> {
    let start_gen = position_to_byte_offset(virtual_ts, start_line, start_character)?;
    let end_gen = position_to_byte_offset(virtual_ts, end_line, end_character)
        .unwrap_or_else(|| start_gen.saturating_add(1));

    let start_mapping = mapping_for_generated_offset(mappings, start_gen)?;
    let src_start = generated_offset_to_source(start_mapping, start_gen);
    let src_end = mapping_for_generated_offset(mappings, end_gen)
        .map(|mapping| generated_offset_to_source(mapping, end_gen))
        .unwrap_or_else(|| {
            let generated_len = end_gen.saturating_sub(start_gen);
            src_start
                .saturating_add(generated_len)
                .min(start_mapping.src_range.end)
        })
        .max(src_start.saturating_add(1));

    let (start_line, start_char) = source_offset_to_position(source, src_start);
    let (end_line, end_char) = source_offset_to_position(source, src_end.min(source.len()));
    Some((start_line, end_line, start_char, end_char))
}

/// Find the mapping whose `src_range` contains `offset`. Prefers the narrowest
/// match so a re-emitted expression (small range) wins over the verbatim region
/// that surrounds it.
fn mapping_for_source_offset(mappings: &[VizeMapping], offset: usize) -> Option<&VizeMapping> {
    mappings
        .iter()
        .filter(|mapping| offset >= mapping.src_range.start && offset < mapping.src_range.end)
        .min_by_key(|mapping| {
            mapping
                .src_range
                .end
                .saturating_sub(mapping.src_range.start)
        })
}

fn mapping_for_generated_offset(mappings: &[VizeMapping], offset: usize) -> Option<&VizeMapping> {
    mappings
        .iter()
        .find(|mapping| offset >= mapping.gen_range.start && offset <= mapping.gen_range.end)
}

fn generated_offset_to_source(mapping: &VizeMapping, generated_offset: usize) -> usize {
    let generated_relative = generated_offset.saturating_sub(mapping.gen_range.start);
    let source_len = mapping
        .src_range
        .end
        .saturating_sub(mapping.src_range.start);
    mapping
        .src_range
        .start
        .saturating_add(generated_relative.min(source_len.saturating_sub(1)))
}

/// Convert a byte offset into an LSP `(line, character)` in `text`, counting
/// columns in UTF-16 code units (the LSP wire unit).
fn byte_offset_to_position(text: &str, offset: usize) -> (u32, u32) {
    source_offset_to_position(text, offset)
}

/// Convert an LSP `(line, character)` (UTF-16 columns) into a byte offset.
fn position_to_byte_offset(text: &str, line: u32, character: u32) -> Option<usize> {
    let mut current_line = 0u32;
    let mut line_start = 0usize;

    for (offset, ch) in text.char_indices() {
        if current_line == line {
            break;
        }
        if ch == '\n' {
            current_line += 1;
            line_start = offset + ch.len_utf8();
        }
    }

    if current_line != line {
        return None;
    }

    let line_text = text[line_start..]
        .split_once('\n')
        .map(|(line, _)| line)
        .unwrap_or(&text[line_start..]);
    let mut utf16_units = 0u32;
    for (relative_offset, ch) in line_text.char_indices() {
        if utf16_units == character {
            return Some(line_start + relative_offset);
        }
        let next_utf16_units = utf16_units + ch.len_utf16() as u32;
        if character < next_utf16_units {
            return None;
        }
        utf16_units = next_utf16_units;
    }

    (utf16_units == character).then_some(line_start + line_text.len())
}

/// Convert a byte offset into an LSP `(line, character)` (UTF-16 columns).
pub(super) fn source_offset_to_position(source: &str, offset: usize) -> (u32, u32) {
    let mut line = 0u32;
    let mut character = 0u32;
    let target = offset.min(source.len());

    for (current, ch) in source.char_indices() {
        if current >= target {
            break;
        }
        if ch == '\n' {
            line += 1;
            character = 0;
        } else {
            character += ch.len_utf16() as u32;
        }
    }

    (line, character)
}

#[cfg(test)]
mod tests {
    use super::*;
    use vize_atelier_jsx::JsxLang;

    fn round_trip(source: &str, marker: &str) {
        let generated = super::super::virtual_ts::generate_jsx_virtual_ts(source, JsxLang::Tsx)
            .expect("generate");
        let source_offset = source.find(marker).expect("marker present");
        let (line, ch) =
            source_offset_to_virtual_position(&generated.code, &generated.mappings, source_offset)
                .expect("forward map");
        // The generated byte at (line, ch) should correspond back to the same
        // source offset region.
        let (src_start, _, _, _) = virtual_range_to_source(
            &generated.code,
            source,
            &generated.mappings,
            line,
            ch,
            line,
            ch + 1,
        )
        .expect("back map");
        let (expected_line, _expected_col) = source_offset_to_position(source, source_offset);
        assert_eq!(
            src_start, expected_line,
            "round-trip landed on a different source line for marker {marker:?}"
        );
    }

    #[test]
    fn maps_props_access_inside_jsx_expr() {
        round_trip(
            "const C = (props: { msg: string }) => <div>{props.msg}</div>;\n",
            "props.msg",
        );
    }

    #[test]
    fn maps_setup_scope_identifier() {
        round_trip(
            "const C = (props: { n: number }) => {\n  const total = props.n + 1;\n  return <span>{total}</span>;\n};\n",
            "props.n + 1",
        );
    }

    /// A member-access completion trigger (`props.|`) inside the setup body
    /// must map into the virtual TS so completion can fire — the setup body is
    /// verbatim, so the cursor lands on the identical generated bytes.
    #[test]
    fn maps_member_access_trigger_in_setup_body() {
        let source = "const C = (props: { msg: string }) => {\n  const x = props.;\n  return <span>{x}</span>;\n};\n";
        let generated =
            super::super::virtual_ts::generate_jsx_virtual_ts(source, JsxLang::Tsx).unwrap();
        // Cursor immediately after the `.` in `props.`.
        let dot = source.find("props.").unwrap() + "props.".len();
        let mapped = source_offset_to_virtual_position(&generated.code, &generated.mappings, dot);
        assert!(
            mapped.is_some(),
            "member-access trigger did not map into virtual TS:\n{}",
            generated.code
        );
    }
}
